PRAGMA user_version = 6;
PRAGMA foreign_keys = ON;

-- ============================================================
-- v6 Golden Fixtures -- synthetic test database
-- 5 tracks covering all analysis states
-- Generated with seed=42 L2-normalised float32 embeddings
-- ============================================================

-- Core tables
CREATE TABLE tracks (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    path TEXT NOT NULL UNIQUE,
    size INTEGER NOT NULL,
    mtime REAL NOT NULL,
    artist TEXT,
    title TEXT,
    album TEXT,
    bpm REAL,
    musical_key TEXT,
    energy REAL,
    duration REAL,
    has_sonara_analysis INTEGER NOT NULL DEFAULT 0,
    has_maest_embedding INTEGER NOT NULL DEFAULT 0,
    has_mert_embedding INTEGER NOT NULL DEFAULT 0,
    has_muq_embedding INTEGER NOT NULL DEFAULT 0,
    has_clap_embedding INTEGER NOT NULL DEFAULT 0,
    metadata_json TEXT NOT NULL DEFAULT '{}' CHECK (json_valid(metadata_json)),
    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE embeddings (
    track_id INTEGER NOT NULL,
    embedding_key TEXT NOT NULL,
    model_name TEXT NOT NULL,
    dim INTEGER NOT NULL,
    vector BLOB NOT NULL,
    updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY(track_id, embedding_key),
    FOREIGN KEY(track_id) REFERENCES tracks(id) ON DELETE CASCADE
);

CREATE TABLE library_settings (
    key TEXT PRIMARY KEY,
    value TEXT NOT NULL,
    updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE track_classifier_scores (
    track_id INTEGER NOT NULL,
    classifier TEXT NOT NULL,
    score REAL NOT NULL,
    label TEXT NOT NULL,
    confidence REAL NOT NULL,
    probabilities_json TEXT NOT NULL CHECK(json_valid(probabilities_json)),
    feature_set TEXT NOT NULL,
    model_id TEXT NOT NULL,
    analyzed_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY(track_id, classifier),
    FOREIGN KEY(track_id) REFERENCES tracks(id) ON DELETE CASCADE
);

CREATE TABLE track_likes (
    track_id INTEGER PRIMARY KEY,
    liked_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY(track_id) REFERENCES tracks(id) ON DELETE CASCADE
);

CREATE TABLE search_sessions (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    mode TEXT NOT NULL,
    seed_track_ids_json TEXT NOT NULL CHECK(json_valid(seed_track_ids_json)),
    request_json TEXT NOT NULL CHECK(json_valid(request_json)),
    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE search_result_events (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    session_id INTEGER NOT NULL REFERENCES search_sessions(id) ON DELETE CASCADE,
    track_id INTEGER NOT NULL REFERENCES tracks(id) ON DELETE CASCADE,
    rank INTEGER NOT NULL,
    total_score REAL NOT NULL,
    score_breakdown_json TEXT NOT NULL CHECK(json_valid(score_breakdown_json)),
    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE track_pair_feedback (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    seed_track_id INTEGER NOT NULL REFERENCES tracks(id) ON DELETE CASCADE,
    candidate_track_id INTEGER NOT NULL REFERENCES tracks(id) ON DELETE CASCADE,
    rating INTEGER NOT NULL CHECK(rating BETWEEN 0 AND 3),
    reason_tags_json TEXT NOT NULL DEFAULT '[]' CHECK(json_valid(reason_tags_json)),
    notes TEXT,
    source TEXT NOT NULL DEFAULT 'manual',
    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
    UNIQUE(seed_track_id, candidate_track_id, source)
);

CREATE TABLE transition_feedback (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    outgoing_track_id INTEGER NOT NULL REFERENCES tracks(id) ON DELETE CASCADE,
    incoming_track_id INTEGER NOT NULL REFERENCES tracks(id) ON DELETE CASCADE,
    rating INTEGER NOT NULL CHECK(rating BETWEEN 0 AND 3),
    risk_tags_json TEXT NOT NULL DEFAULT '[]' CHECK(json_valid(risk_tags_json)),
    notes TEXT,
    source TEXT NOT NULL DEFAULT 'manual',
    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE calibration_runs (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    profile_name TEXT NOT NULL,
    search_mode TEXT NOT NULL,
    config_json TEXT NOT NULL CHECK(json_valid(config_json)),
    metrics_json TEXT NOT NULL CHECK(json_valid(metrics_json)),
    created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP
);

-- FTS5 virtual table
CREATE VIRTUAL TABLE track_search_fts USING fts5(
    track_id UNINDEXED,
    search_text,
    tokenize = 'unicode61'
);

-- Indexes
CREATE INDEX idx_tracks_sort_artist_title_path ON tracks (COALESCE(artist, ''), COALESCE(title, ''), path);
CREATE INDEX idx_tracks_syncopated_sort ON tracks(COALESCE(artist, ''), COALESCE(title, ''), path) WHERE json_extract(metadata_json, '$.maest_syncopated_rhythm') = 1;
CREATE INDEX idx_tracks_missing_sonara_flag_sort ON tracks(COALESCE(artist, ''), COALESCE(title, ''), path) WHERE has_sonara_analysis = 0;
CREATE INDEX idx_tracks_missing_maest_embedding_flag_sort ON tracks(COALESCE(artist, ''), COALESCE(title, ''), path) WHERE has_maest_embedding = 0;
CREATE INDEX idx_tracks_missing_mert_embedding_flag_sort ON tracks(COALESCE(artist, ''), COALESCE(title, ''), path) WHERE has_mert_embedding = 0;
CREATE INDEX idx_tracks_missing_muq_embedding_flag_sort ON tracks(COALESCE(artist, ''), COALESCE(title, ''), path) WHERE has_muq_embedding = 0;
CREATE INDEX idx_tracks_missing_clap_embedding_flag_sort ON tracks(COALESCE(artist, ''), COALESCE(title, ''), path) WHERE has_clap_embedding = 0;
CREATE INDEX idx_tracks_present_sonara_flag ON tracks(id) WHERE has_sonara_analysis = 1;
CREATE INDEX idx_tracks_present_maest_embedding_flag ON tracks(id) WHERE has_maest_embedding = 1;
CREATE INDEX idx_tracks_present_mert_embedding_flag ON tracks(id) WHERE has_mert_embedding = 1;
CREATE INDEX idx_tracks_present_muq_embedding_flag ON tracks(id) WHERE has_muq_embedding = 1;
CREATE INDEX idx_tracks_present_clap_embedding_flag ON tracks(id) WHERE has_clap_embedding = 1;
CREATE INDEX idx_embeddings_key_track ON embeddings(embedding_key, track_id);
CREATE INDEX idx_classifier_scores_lookup ON track_classifier_scores(classifier, score DESC, track_id);
CREATE INDEX idx_search_sessions_mode_created ON search_sessions(mode, created_at);
CREATE INDEX idx_search_result_events_session_rank ON search_result_events(session_id, rank);
CREATE INDEX idx_search_result_events_track ON search_result_events(track_id);
CREATE INDEX idx_track_pair_feedback_seed_rating ON track_pair_feedback(seed_track_id, rating, candidate_track_id);
CREATE INDEX idx_track_pair_feedback_candidate ON track_pair_feedback(candidate_track_id);
CREATE INDEX idx_transition_feedback_outgoing_created ON transition_feedback(outgoing_track_id, created_at);
CREATE INDEX idx_transition_feedback_incoming ON transition_feedback(incoming_track_id);
CREATE INDEX idx_calibration_runs_profile_mode_created ON calibration_runs(profile_name, search_mode, created_at);

-- Triggers
CREATE TRIGGER tracks_metadata_json_insert_valid
BEFORE INSERT ON tracks
FOR EACH ROW
WHEN NOT json_valid(NEW.metadata_json)
BEGIN
    SELECT RAISE(ABORT, 'tracks.metadata_json must be valid JSON');
END;

CREATE TRIGGER tracks_metadata_json_update_valid
BEFORE UPDATE OF metadata_json ON tracks
FOR EACH ROW
WHEN NOT json_valid(NEW.metadata_json)
BEGIN
    SELECT RAISE(ABORT, 'tracks.metadata_json must be valid JSON');
END;

