-- FTS population
INSERT INTO track_search_fts(rowid, track_id, search_text)
SELECT t.id, t.id,
    COALESCE(t.artist, '') || ' ' ||
    COALESCE(t.title, '') || ' ' ||
    COALESCE(t.album, '') || ' ' ||
    t.path || ' ' ||
    t.metadata_json
FROM tracks t
ORDER BY t.id;
